  auto check_hybrid_handoff() -> std::optional<int>
  {
    if constexpr (!requires { cpu.get_committed_pc(); }) {
      return std::nullopt;
    } else {
      const auto committed = cpu.get_committed_pc();
      if (committed.empty()) return std::nullopt;
      for (const auto pc: committed[0]) {
        auto state = hybrid_handoff_->on_retire(
          pc, [&](uint8_t r) -> uint64_t {
            if constexpr (requires { cpu.get_gpr(r); }) {
              return cpu.get_gpr(r);
            }
            return 0;
          });
        if (state) {
          // V-register merge: the fixture's vsim-phase epilogue is expected
          // to have run vse8.v v0..v31 to scratch RAM before the exit
          // trigger fired. Read those bytes back into state.vreg[] so the
          // gdbstub-driven QEMU 2 restore sees vsim's actual values, not
          // QEMU 1's stale snapshot.
          if ((state->flags & HYBRID_FLAG_V) != 0u) {
            hybrid::read_v_from_scratch(
              *state,
              std::span<const uint8_t>{platform.main_memory.data.data(),
                                       platform.main_memory.data.size()},
              platform.main_memory.region.base_address);
          }
          spdlog::info("hybrid handoff: drained at pc=0x{:x}, writing {}",
                       pc, hybrid_state_path_);
          std::ofstream f(hybrid_state_path_, std::ios::binary);
          f.write(reinterpret_cast<const char*>(&*state), sizeof(*state));
          return hybrid::kExitHandoffToQemu;
        }
      }
      return std::nullopt;
    }
  }

