static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
{
    (void) id;
    size_t n = qemu_plugin_tb_n_insns(tb);
    for (size_t i = 0; i < n; i++) {
        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);

        if (pc_mode) {
            // PC-trigger mode: vaddr-only match. qemu_plugin_insn_size lets
            // a future fixture park enter_pc on a compressed insn -- next-PC
            // is computed from the API-reported size, not assumed to be 4.
            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
            HandoffSite *site = g_new0(HandoffSite, 1);
            site->kind  = HYBRID_HANDOFF_ENTER;
            site->vaddr = qemu_plugin_insn_vaddr(insn);
            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
            qemu_plugin_register_vcpu_insn_exec_cb(
                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
            continue;
        }

        // CSR-trigger mode (default).
        size_t sz = qemu_plugin_insn_size(insn);
        if (sz != 4) continue;
        uint32_t raw = 0;
        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
            continue;
        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
        HandoffSite *site = g_new0(HandoffSite, 1);
        site->kind  = kind;
        site->vaddr = qemu_plugin_insn_vaddr(insn);
        site->size  = (uint32_t) sz;
        qemu_plugin_register_vcpu_insn_exec_cb(
            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
    }
}

QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
                                           const qemu_info_t *info,
                                           int argc, char **argv)
{
    (void) info;
    for (int i = 0; i < argc; i++) {
        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
            outfile_path = g_strdup(tok[1]);
        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
            char *endp = NULL;
            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
            if (!endp || *endp != '\0') {
                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
                        tok[1]);
                return -1;
            }
            enter_pc_arg = (uint64_t) v;
            pc_mode = 1;
        } else {
            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
            return -1;
        }
    }
    if (!outfile_path) {
        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
        return -1;
    }
    if (pc_mode) {
        fprintf(stderr,
                "hybrid_handoff: PC-mode enter=0x%" PRIx64 "\n",
                enter_pc_arg);
    }

    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
    return 0;
}

