// TCP-backed GDB Remote Serial Protocol session. Wraps an already-connected
// socket fd; the higher-level qemu_handback orchestration spawns QEMU and
// passes the fd in.

#pragma once

#include "hybrid/gdbstub_client.hpp"

#include <spdlog/spdlog.h>

#include <sys/socket.h>
#include <sys/time.h>
#include <unistd.h>

#include <cerrno>
#include <cstdint>
#include <cstring>
#include <stdexcept>
#include <string>
#include <string_view>

namespace hybrid::gdbstub
{

class Session
{
public:
  // 5 s recv timeout: a peer that opens the gdbstub port but never replies
  // (e.g. a misbehaving QEMU build) must not hang vsim indefinitely.
  static constexpr long kRecvTimeoutSeconds = 5;

  explicit Session(int fd)
      : fd_{fd}
  {
    timeval tv{kRecvTimeoutSeconds, 0};
    ::setsockopt(fd_, SOL_SOCKET, SO_RCVTIMEO, &tv, sizeof(tv));
  }

  Session(const Session&)            = delete;
  Session& operator=(const Session&) = delete;

  Session(Session&& o) noexcept
      : fd_{o.fd_}
  {
    o.fd_ = -1;
  }

  ~Session()
  {
    if (fd_ >= 0) ::close(fd_);
  }

  // Sends $body#cs, waits for `+` ack, reads and acks one response packet,
  // returns the response body. Throws on socket errors or protocol violations.
  auto send_command(std::string_view body) -> std::string
  {
    const auto pkt = encode_packet(body);
    spdlog::debug("gdbstub send: {}", pkt);
    send_raw(pkt);
    expect_ack();
    auto resp = recv_packet();
    spdlog::debug("gdbstub recv: {}", resp);
    send_raw("+");
    return resp;
  }

  // Sends $c#cs and waits only for the ack. The target runs until it exits
  // on its own (e.g., semihosting) -- caller waitpid()s the QEMU process.
  void cont()
  {
    send_raw(encode_continue());
    expect_ack();
  }

private:
  void send_raw(std::string_view data)
  {
    std::size_t off = 0;
    while (off < data.size()) {
      const ssize_t n =
        ::send(fd_, data.data() + off, data.size() - off, 0);
      if (n < 0) {
        if (errno == EINTR) continue;
        throw std::runtime_error(std::string{"gdbstub::Session::send: "}
                                 + std::strerror(errno));
      }
      off += static_cast<std::size_t>(n);
    }
  }

  auto recv_byte() -> char
  {
    char c;
    while (true) {
      const ssize_t n = ::recv(fd_, &c, 1, 0);
      if (n == 1) return c;
      if (n == 0)
        throw std::runtime_error("gdbstub::Session: peer closed");
      if (errno == EINTR) continue;
      if (errno == EAGAIN || errno == EWOULDBLOCK)
        throw std::runtime_error("gdbstub::Session: recv timeout");
      throw std::runtime_error(std::string{"gdbstub::Session::recv: "}
                               + std::strerror(errno));
    }
  }

  void expect_ack()
  {
    const auto c = recv_byte();
    if (c == '+') return;
    if (c == '-')
      throw std::runtime_error("gdbstub::Session: peer requested resend");
    throw std::runtime_error(
      std::string{"gdbstub::Session: expected ack, got "} + c);
  }

  // Reads `$body#cs`, validates checksum, returns body. Discards any leading
  // out-of-frame bytes (some stubs emit unsolicited stop notifications).
  auto recv_packet() -> std::string
  {
    while (recv_byte() != '$') {}
    std::string body;
    while (true) {
      const auto c = recv_byte();
      if (c == '#') break;
      body.push_back(c);
    }
    const auto cs_hi = recv_byte();
    const auto cs_lo = recv_byte();
    const std::string framed = "$" + body + "#" + cs_hi + cs_lo;
    auto parsed = parse_packet(framed);
    if (!parsed)
      throw std::runtime_error("gdbstub::Session: bad checksum");
    return *parsed;
  }

  int fd_;
};

}  // namespace hybrid::gdbstub

// Shared GDB register-name tables. Used by the QEMU TCG plugin (C) at
// drain time and by vsim's gdbstub handback client (C++) at restore
// time. The strings are the gdb wire contract for QEMU's RISC-V
// gdbstub - any reordering or renaming must be done in lock-step here.

#ifndef HYBRID_REG_NAMES_H
#define HYBRID_REG_NAMES_H

#ifdef __cplusplus
extern "C" {
#endif

// Index = x register index. Matches the names in QEMU's
// gdb-xml/riscv-64bit-cpu.xml (the wire contract for qemu_plugin_register
// lookup). NB: x8 is "fp", NOT "s0" -- QEMU's gdbstub uses the
// frame-pointer alias. Looking it up as "s0" yields a NULL handle and
// silently zeros gpr[8] in the drained state.
static const char *const hybrid_gpr_names[32] = {
    "zero", "ra",  "sp",  "gp",  "tp",  "t0", "t1", "t2",
    "fp",   "s1",  "a0",  "a1",  "a2",  "a3", "a4", "a5",
    "a6",   "a7",  "s2",  "s3",  "s4",  "s5", "s6", "s7",
    "s8",   "s9",  "s10", "s11", "t3",  "t4", "t5", "t6",
};

// Index = f register index. From riscv-64bit-fpu.xml.
static const char *const hybrid_fpr_names[32] = {
    "ft0", "ft1", "ft2",  "ft3",  "ft4", "ft5", "ft6", "ft7",
    "fs0", "fs1", "fa0",  "fa1",  "fa2", "fa3", "fa4", "fa5",
    "fa6", "fa7", "fs2",  "fs3",  "fs4", "fs5", "fs6", "fs7",
    "fs8", "fs9", "fs10", "fs11", "ft8", "ft9", "ft10","ft11",
};

#ifdef __cplusplus
}  // extern "C"
#endif

#endif  // HYBRID_REG_NAMES_H

