// GDB Remote Serial Protocol encoders/parsers for the vsim->QEMU resume
// path. The TCP transport is layered on top in hybrid/gdbstub_session.hpp.
//
// Only the subset needed for register restore is implemented:
//   - $body#cksum framing
//   - `P<reg>=<value>` write-register (8-byte and variable-width forms)
//   - `c` continue
//   - `qXfer:features:read:...` target-description discovery
// Run-length-encoded responses (rare in modern stubs) are not handled.

#pragma once

#include <array>
#include <cstdint>
#include <optional>
#include <string>
#include <string_view>
#include <unordered_map>
#include <vector>

namespace hybrid::gdbstub
{

inline auto compute_checksum(std::string_view body) -> uint8_t
{
  unsigned sum = 0;
  for (char c : body) sum += static_cast<unsigned char>(c);
  return static_cast<uint8_t>(sum & 0xFFu);
}

namespace detail
{

inline auto hex_nybble(unsigned v) -> char
{
  return static_cast<char>(v < 10 ? '0' + v : 'a' + (v - 10));
}

inline void append_hex_byte(std::string& out, uint8_t b)
{
  out.push_back(hex_nybble((b >> 4) & 0xFu));
  out.push_back(hex_nybble(b & 0xFu));
}

inline auto from_hex(char c) -> std::optional<unsigned>
{
  if (c >= '0' && c <= '9') return static_cast<unsigned>(c - '0');
  if (c >= 'a' && c <= 'f') return static_cast<unsigned>(c - 'a' + 10);
  if (c >= 'A' && c <= 'F') return static_cast<unsigned>(c - 'A' + 10);
  return std::nullopt;
}

}  // namespace detail

inline auto encode_packet(std::string_view body) -> std::string
{
  std::string out;
  out.reserve(body.size() + 4);
  out.push_back('$');
  out.append(body);
  out.push_back('#');
  detail::append_hex_byte(out, compute_checksum(body));
  return out;
}

namespace detail
{

// Emits a register number in the minimum number of hex nibbles. CSR-feature
// regnums in QEMU's RISC-V gdbstub run up to ~3000, so 2-nibble encodings
// silently truncate and clobber a low-numbered register.
inline void append_reg_num_hex(std::string& out, unsigned reg_num)
{
  if (reg_num == 0) {
    out.push_back('0');
    return;
  }
  unsigned shift = 0;
  unsigned tmp   = reg_num;
  while (tmp >= 16) { tmp >>= 4; shift += 4; }
  while (true) {
    out.push_back(hex_nybble((reg_num >> shift) & 0xFu));
    if (shift == 0) break;
    shift -= 4;
  }
}

}  // namespace detail

// Body of a `P<reg-hex>=<value-bytes-le-hex>` packet (no $...# framing).
// reg is the GDB register number (0..31 for GPR, 32 for pc on RV64, 3-digit
// regnums for CSR-feature entries). value is encoded as 8 little-endian bytes.
inline auto encode_p_body(unsigned reg_num, uint64_t value) -> std::string
{
  std::string body;
  body.push_back('P');
  detail::append_reg_num_hex(body, reg_num);
  body.push_back('=');
  for (unsigned i = 0; i < 8; ++i) {
    detail::append_hex_byte(body, static_cast<uint8_t>(value & 0xFFu));
    value >>= 8;
  }
  return body;
}

inline auto encode_p_packet(unsigned reg_num, uint64_t value) -> std::string
{
  return encode_packet(encode_p_body(reg_num, value));
}

// `P<reg>=<bytes-le-hex>` body for arbitrary-width payloads (e.g. vector
// regs whose width = vlenb bytes).
inline auto encode_p_body_bytes(unsigned reg_num,
                                const uint8_t* bytes,
                                std::size_t n) -> std::string
{
  std::string body;
  body.reserve(4 + n * 2);
  body.push_back('P');
  detail::append_reg_num_hex(body, reg_num);
  body.push_back('=');
  for (std::size_t i = 0; i < n; ++i) detail::append_hex_byte(body, bytes[i]);
  return body;
}

inline auto encode_continue() -> std::string
{
  return encode_packet("c");
}

// Parses one $body#cksum frame and returns the body iff the checksum matches.
inline auto parse_packet(std::string_view raw) -> std::optional<std::string>
{
  if (raw.size() < 4 || raw.front() != '$') return std::nullopt;
  const auto hash = raw.find('#');
  if (hash == std::string_view::npos) return std::nullopt;
  if (raw.size() < hash + 3) return std::nullopt;

  const auto body = raw.substr(1, hash - 1);
  const auto cs_hi = detail::from_hex(raw[hash + 1]);
  const auto cs_lo = detail::from_hex(raw[hash + 2]);
  if (!cs_hi || !cs_lo) return std::nullopt;

  const auto expected = static_cast<uint8_t>((*cs_hi << 4) | *cs_lo);
  if (expected != compute_checksum(body)) return std::nullopt;

  return std::string{body};
}

// Map from gdb register name (e.g. "mstatus", "ft0") -> packet register
// number used in `P<reg>=...` and `g`/`G`. Built by walking target.xml +
// each `<xi:include>` annex.
class RegMap
{
public:
  void insert(std::string name, unsigned reg_num)
  {
    table_.emplace(std::move(name), reg_num);
  }

  auto find(const std::string& name) const -> std::optional<unsigned>
  {
    const auto it = table_.find(name);
    if (it == table_.end()) return std::nullopt;
    return it->second;
  }

  auto size() const -> std::size_t { return table_.size(); }

private:
  std::unordered_map<std::string, unsigned> table_;
};

// Extracts the value of an attribute from one XML element start tag.
// `tag_start` points at the '<' of the tag; the search runs until the
// matching '>' or the end of the string.
inline auto extract_attr(std::string_view xml,
                         std::size_t tag_start,
                         std::string_view name) -> std::optional<std::string>
{
  const auto end = xml.find('>', tag_start);
  if (end == std::string_view::npos) return std::nullopt;
  const auto window = xml.substr(tag_start, end - tag_start);
  std::string needle{name};
  needle.append("=\"");
  const auto k = window.find(needle);
  if (k == std::string_view::npos) return std::nullopt;
  const auto v_begin = k + needle.size();
  const auto v_end   = window.find('"', v_begin);
  if (v_end == std::string_view::npos) return std::nullopt;
  return std::string{window.substr(v_begin, v_end - v_begin)};
}

// Walks a single feature XML body (the contents of one annex), extracting
// `<reg name="X" .../>` entries into the map. `next_unnumbered` is updated
// with the cumulative count of regs seen across all features so far; an
// explicit `regnum="N"` attribute overrides the counter for that one entry
// without changing the running total (QEMU's CSR feature uses sparse
// regnums, so each subsequent unnumbered entry would be ill-defined - in
// practice the CSR feature is the last one parsed).
inline void parse_feature_xml(std::string_view xml,
                              RegMap& map,
                              unsigned& next_unnumbered)
{
  std::size_t pos = 0;
  while (true) {
    const auto p = xml.find("<reg ", pos);
    if (p == std::string_view::npos) break;
    pos = p + 5;
    const auto name   = extract_attr(xml, p, "name");
    const auto regnum = extract_attr(xml, p, "regnum");
    if (!name) continue;
    unsigned id = next_unnumbered;
    if (regnum) {
      try {
        id = static_cast<unsigned>(std::stoul(*regnum));
      } catch (...) {
        id = next_unnumbered++;
      }
    } else {
      ++next_unnumbered;
    }
    map.insert(*name, id);
  }
}

// Pulls each `<xi:include href="X"/>` href out of target.xml in declaration
// order. The order is significant: each annex extends the cumulative
// register-number counter from where the previous feature left off.
inline auto parse_target_xml(std::string_view xml) -> std::vector<std::string>
{
  std::vector<std::string> annexes;
  std::size_t pos = 0;
  while (true) {
    const auto p = xml.find("<xi:include", pos);
    if (p == std::string_view::npos) break;
    if (auto href = extract_attr(xml, p, "href")) annexes.push_back(*href);
    pos = p + 11;
  }
  return annexes;
}

}  // namespace hybrid::gdbstub

