1	// QEMU TCG plugin: drains architectural state and exits when the guest
2	// executes `csrwi 0x7C0, 0`. Shares hybrid/insn_match.h and
3	// hybrid/state_abi.h with the vsim side.
4	
5	#include "hybrid/handoff_site.h"
6	#include "hybrid/insn_match.h"
7	#include "hybrid/reg_names.h"
8	#include "hybrid/state_abi.h"
9	
10	#include <qemu-plugin.h>
11	
12	#include <glib.h>
13	
14	#include <fcntl.h>
15	#include <inttypes.h>
16	#include <stddef.h>
17	#include <stdint.h>
18	#include <stdio.h>
19	#include <stdlib.h>
20	#include <string.h>
21	#include <unistd.h>
22	#include <limits.h>
23	
24	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
25	
26	typedef struct {
27	    struct qemu_plugin_register *gpr[32];
28	    struct qemu_plugin_register *fpr[32];
29	    struct qemu_plugin_register *pc;
30	
31	    // M-mode CSRs as exposed by QEMU's gdbstub csr feature.
32	    struct qemu_plugin_register *mstatus;
33	    struct qemu_plugin_register *mepc;
34	    struct qemu_plugin_register *mtvec;
35	    struct qemu_plugin_register *mcause;
36	    struct qemu_plugin_register *mtval;
37	    struct qemu_plugin_register *mscratch;
38	    struct qemu_plugin_register *medeleg;
39	    struct qemu_plugin_register *mideleg;
40	    struct qemu_plugin_register *mip;
41	    struct qemu_plugin_register *mie;
42	    struct qemu_plugin_register *mcycle;
43	    struct qemu_plugin_register *minstret;
44	    struct qemu_plugin_register *satp;
45	
46	    struct qemu_plugin_register *pmpcfg[HYBRID_PMP_CFG_NUM];
47	    struct qemu_plugin_register *pmpaddr[HYBRID_PMP_ADDR_NUM];
48	
49	    struct qemu_plugin_register *vstart;
50	    struct qemu_plugin_register *vxsat;
51	    struct qemu_plugin_register *vxrm;
52	    struct qemu_plugin_register *vcsr;
53	    struct qemu_plugin_register *vtype;
54	    struct qemu_plugin_register *vl;
55	    struct qemu_plugin_register *vlenb;
56	    struct qemu_plugin_register *vreg[32];
57	} VcpuRegs;
58	
59	static struct qemu_plugin_scoreboard *vcpu_state;
60	static char *outfile_path;
61	
62	// PC-trigger mode: when enter_pc_arg is non-zero (set via plugin arg
63	// `enter_pc=0x...`), the CSR-insn matcher is bypassed entirely and the
64	// drain callback is registered only for instructions whose vaddr equals
65	// enter_pc_arg. The kind reported on the drain is HYBRID_HANDOFF_ENTER
66	// (entry into vsim), matching CSR-mode `csrwi 0x7C0, 0` semantics.
67	static uint64_t enter_pc_arg;
68	static int pc_mode;
69	
70	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
71	{
72	    for (guint i = 0; i < regs->len; i++) {
73	        qemu_plugin_reg_descriptor *rd =
74	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
75	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
76	            return rd->handle;
77	        }
78	    }
79	    return NULL;
80	}
81	
82	// Lazily resolves register handles. The plugin's vcpu_init runs before
83	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
84	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
85	// regs at that moment. By the time the entry trigger fires, all dynamic
86	// features are registered and a fresh call returns the full list.
87	static void resolve_handles(VcpuRegs *v)
88	{
89	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
90	    for (int i = 0; i < 32; i++) {
91	        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
92	        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
93	    }
94	    v->pc = find_reg(regs, "pc");
95	
96	    v->mstatus  = find_reg(regs, "mstatus");
97	    v->mepc     = find_reg(regs, "mepc");
98	    v->mtvec    = find_reg(regs, "mtvec");
99	    v->mcause   = find_reg(regs, "mcause");
100	    v->mtval    = find_reg(regs, "mtval");
101	    v->mscratch = find_reg(regs, "mscratch");
102	    v->medeleg  = find_reg(regs, "medeleg");
103	    v->mideleg  = find_reg(regs, "mideleg");
104	    v->mip      = find_reg(regs, "mip");
105	    v->mie      = find_reg(regs, "mie");
106	    v->mcycle   = find_reg(regs, "mcycle");
107	    v->minstret = find_reg(regs, "minstret");
108	    v->satp     = find_reg(regs, "satp");
109	
110	    char buf[16];
111	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++) {
112	        g_snprintf(buf, sizeof(buf), "pmpcfg%d", i);
113	        v->pmpcfg[i] = find_reg(regs, buf);
114	    }
115	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++) {
116	        g_snprintf(buf, sizeof(buf), "pmpaddr%d", i);
117	        v->pmpaddr[i] = find_reg(regs, buf);
118	    }
119	
120	    v->vstart = find_reg(regs, "vstart");
121	    v->vxsat  = find_reg(regs, "vxsat");
122	    v->vxrm   = find_reg(regs, "vxrm");
123	    v->vcsr   = find_reg(regs, "vcsr");
124	    v->vtype  = find_reg(regs, "vtype");
125	    v->vl     = find_reg(regs, "vl");
126	    v->vlenb  = find_reg(regs, "vlenb");
127	    for (int i = 0; i < 32; i++) {
128	        g_snprintf(buf, sizeof(buf), "v%d", i);
129	        v->vreg[i] = find_reg(regs, buf);
130	    }
131	}
132	
133	static uint64_t read_reg64(struct qemu_plugin_register *h)
134	{
135	    if (!h) return 0;
136	    g_autoptr(GByteArray) buf = g_byte_array_new();
137	    int sz = qemu_plugin_read_register(h, buf);
138	    if (sz <= 0) return 0;
139	    uint64_t v = 0;
140	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
141	    return v;
142	}
143	
144	// Reads up to `dst_max` bytes from a register handle. Returns the byte
145	// count written (0 on failure or NULL handle). Used for vector regs whose
146	// width = vlenb bytes.
147	static size_t read_reg_bytes(struct qemu_plugin_register *h,
148	                             uint8_t *dst, size_t dst_max)
149	{
150	    if (!h || dst_max == 0) return 0;
151	    g_autoptr(GByteArray) buf = g_byte_array_new();
152	    int sz = qemu_plugin_read_register(h, buf);
153	    if (sz <= 0) return 0;
154	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
155	    memcpy(dst, buf->data, n);
156	    return n;
157	}
158	
159	// Atomic on POSIX: write to .tmp, fsync, rename.
160	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
161	{
162	    char tmp[PATH_MAX];
163	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
164	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
165	    if (fd < 0) {
166	        perror("hybrid_handoff: open tmp");
167	        return -1;
168	    }
169	    ssize_t want = (ssize_t) sizeof(*s);
170	    ssize_t got = write(fd, s, sizeof(*s));
171	    if (got != want) {
172	        perror("hybrid_handoff: write");
173	        close(fd);
174	        unlink(tmp);
175	        return -1;
176	    }
177	    fsync(fd);
178	    close(fd);
179	    if (rename(tmp, path) != 0) {
180	        perror("hybrid_handoff: rename");
181	        unlink(tmp);
182	        return -1;
183	    }
184	    return 0;
185	}
186	
187	static void on_handoff(unsigned int vcpu_idx, void *udata)
188	{
189	    const HandoffSite *site = (const HandoffSite *) udata;
190	    if (site->kind != HYBRID_HANDOFF_ENTER) return;
191	
192	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
193	    resolve_handles(v);
194	    struct hybrid_state_v1 s = {0};
195	    s.magic   = HYBRID_STATE_MAGIC;
196	    s.version = HYBRID_STATE_VERSION;
197	    s.flags   = HYBRID_FLAG_RV64;
198	    s.hart_id = vcpu_idx;
199	    s.priv    = 3;
200	    // PC via translation-time vaddr+size; reading the gdbstub PC inside the
201	    // exec callback can lag the actual current insn when V instructions
202	    // retire just before the trigger (TCG defers PC writes for performance).
203	    s.pc      = compute_handoff_pc(site);
204	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
205	
206	    // Floating-point: only set FP flag if at least one handle was bound,
207	    // i.e. QEMU advertised the FPU feature (D extension).
208	    int has_fp = 0;
209	    for (int i = 0; i < 32; i++) {
210	        s.fpr[i] = read_reg64(v->fpr[i]);
211	        if (v->fpr[i]) has_fp = 1;
212	    }
213	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
214	
215	    s.mstatus  = read_reg64(v->mstatus);
216	    s.mepc     = read_reg64(v->mepc);
217	    s.mtvec    = read_reg64(v->mtvec);
218	    s.mcause   = read_reg64(v->mcause);
219	    s.mtval    = read_reg64(v->mtval);
220	    s.mscratch = read_reg64(v->mscratch);
221	    s.medeleg  = read_reg64(v->medeleg);
222	    s.mideleg  = read_reg64(v->mideleg);
223	    s.mip      = read_reg64(v->mip);
224	    s.mie      = read_reg64(v->mie);
225	    s.mcycle   = read_reg64(v->mcycle);
226	    s.minstret = read_reg64(v->minstret);
227	    s.satp     = read_reg64(v->satp);
228	
229	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
230	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
231	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
232	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
233	
234	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
235	    // bounds the per-register byte count copied into vreg[].
236	    s.vstart = read_reg64(v->vstart);
237	    s.vxsat  = read_reg64(v->vxsat);
238	    s.vxrm   = read_reg64(v->vxrm);
239	    s.vcsr   = read_reg64(v->vcsr);
240	    s.vtype  = read_reg64(v->vtype);
241	    s.vl     = read_reg64(v->vl);
242	    s.vlenb  = read_reg64(v->vlenb);
243	    if (v->vlenb && s.vlenb > 0) {
244	        s.flags |= HYBRID_FLAG_V;
245	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
246	                     ? (size_t) s.vlenb
247	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
248	        for (int i = 0; i < 32; i++)
249	            (void) read_reg_bytes(v->vreg[i],
250	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
251	                                  bytes);
252	    }
253	
254	    if (write_state_atomic(&s, outfile_path) != 0) {
255	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
256	        exit(2);
257	    }
258	    fprintf(stderr,
259	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
260	            outfile_path, s.pc);
261	    // 200 == kExitHandoffToQemu in hybrid_vsim/src/hybrid/exit_codes.hpp.
262	    // Distinguishes drain from workload completion (0) so the orchestrator
263	    // can decide the next spawn.
264	    exit(200);
265	}
266	
267	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
268	{
269	    (void) id;
270	    size_t n = qemu_plugin_tb_n_insns(tb);
271	    for (size_t i = 0; i < n; i++) {
272	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
273	
274	        if (pc_mode) {
275	            // PC-trigger mode: vaddr-only match. qemu_plugin_insn_size lets
276	            // a future fixture park enter_pc on a compressed insn -- next-PC
277	            // is computed from the API-reported size, not assumed to be 4.
278	            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
279	            HandoffSite *site = g_new0(HandoffSite, 1);
280	            site->kind  = HYBRID_HANDOFF_ENTER;
281	            site->vaddr = qemu_plugin_insn_vaddr(insn);
282	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
283	            qemu_plugin_register_vcpu_insn_exec_cb(
284	                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
285	            continue;
286	        }
287	
288	        // CSR-trigger mode (default).
289	        size_t sz = qemu_plugin_insn_size(insn);
290	        if (sz != 4) continue;
291	        uint32_t raw = 0;
292	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
293	            continue;
294	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
295	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
296	        HandoffSite *site = g_new0(HandoffSite, 1);
297	        site->kind  = kind;
298	        site->vaddr = qemu_plugin_insn_vaddr(insn);
299	        site->size  = (uint32_t) sz;
300	        qemu_plugin_register_vcpu_insn_exec_cb(
301	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
302	    }
303	}
