312	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
313	            outfile_path = g_strdup(tok[1]);
314	        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
315	            char *endp = NULL;
316	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
317	            if (!endp || *endp != '\0') {
318	                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
319	                        tok[1]);
320	                return -1;
321	            }
