323	            pc_mode = 1;
324	        } else {
325	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
326	            return -1;
327	        }
328	    }
329	    if (!outfile_path) {
330	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
331	        return -1;
332	    }
