// End-to-end roundtrip fixture:
//   1. QEMU + plugin sees `csrwi 0x7C0, 0` -> drains state, exits.
//   2. vsim resumes, computes a2=3.
//   3. vsim sees `csrwi 0x7C0, 1` -> drains state, exits 200.
//   4. main spawns qemu-system -gdb -S -semihosting; resume restores GPRs.
//   5. QEMU runs to the semihosting EXIT_EXTENDED triple and exits with a1=3.

#include "semihost_exit.inc"

.section .text
.globl _start
.globl _hybrid_enter_pc
.globl _hybrid_exit_pc
_start:
_hybrid_enter_pc:
    csrwi   0x7C0, 0          // entry: QEMU drains, exits (CSR mode)
                              //        OR PC drain at _hybrid_enter_pc (PC mode)
    li      a0, 1
    li      a1, 2
    add     a2, a0, a1        // a2 = 3, computed in vsim only
_hybrid_exit_pc:
    csrwi   0x7C0, 1          // exit: vsim drains, exit 200
    SEMIHOST_EXIT a2

