    if (sigaction(SIGINT, &oact, nullptr) == -1)
      perror("sigaction");
  }};

  // wait for debugger connections
  while (dtm_debug && !dtm.is_connected()) {
    dtm.try_accept_socket();
    if (ctrlc != 0) {
      return 130;
    }
    sleep(1);
  }

  [[maybe_unused]]
  bool ctx_resuming = context_config.continue_from;
  [[maybe_unused]]
  bool ctx_triggered = false;

  for (auto n = uint64_t{0}; n < max_cycles; ++n) {

