TEST_CASE("HandoffController<IcountTrigger>: drains at exactly the Nth retire")
{
  RecordingBus bus;
  prime_drainable_bus(bus, /*dpc=*/0x80000400);

  hybrid::IcountTrigger trigger(/*target=*/100);
  hybrid::HandoffController h(std::move(trigger), bus);

  // 99 retires must not fire
  for (int i = 0; i < 99; ++i) {
    const auto state =
      h.on_retire(0x80000000, [](uint8_t) -> uint64_t { return 0u; });
    CHECK_FALSE(state.has_value());
  }
  // 100th retire fires the drain
  const auto state =
    h.on_retire(0x80000000, [](uint8_t) -> uint64_t { return 0u; });
  REQUIRE(state);
  CHECK(state->magic == HYBRID_STATE_MAGIC);
  CHECK(state->pc == 0x80000400);
}

TEST_CASE("HandoffController<IcountTrigger>: target=1 fires on the first retire")
{
  RecordingBus bus;
  prime_drainable_bus(bus, /*dpc=*/0x80000020);

  hybrid::IcountTrigger trigger(/*target=*/1);
  hybrid::HandoffController h(std::move(trigger), bus);

  const auto state =
    h.on_retire(0x80000000, [](uint8_t) -> uint64_t { return 0u; });
  REQUIRE(state);
  CHECK(state->pc == 0x80000020);
}

