94	// Lazily resolves register handles. The plugin's vcpu_init runs before
95	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
96	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
97	// regs at that moment. By the time the entry trigger fires, all dynamic
98	// features are registered and a fresh call returns the full list.
99	static void resolve_handles(VcpuRegs *v)
100	{
101	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
102	    for (int i = 0; i < 32; i++) {
