156	// Reads up to `dst_max` bytes from a register handle. Returns the byte
157	// count written (0 on failure or NULL handle). Used for vector regs whose
158	// width = vlenb bytes.
159	static size_t read_reg_bytes(struct qemu_plugin_register *h,
160	                             uint8_t *dst, size_t dst_max)
161	{
162	    if (!h || dst_max == 0) return 0;
163	    g_autoptr(GByteArray) buf = g_byte_array_new();
164	    int sz = qemu_plugin_read_register(h, buf);
165	    if (sz <= 0) return 0;
166	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
167	    memcpy(dst, buf->data, n);
