171	// Atomic on POSIX: write to .tmp, fsync, rename.
172	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
173	{
174	    char tmp[PATH_MAX];
175	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
176	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
177	    if (fd < 0) {
178	        perror("hybrid_handoff: open tmp");
179	        return -1;
180	    }
181	    ssize_t want = (ssize_t) sizeof(*s);
182	    ssize_t got = write(fd, s, sizeof(*s));
183	    if (got != want) {
184	        perror("hybrid_handoff: write");
185	        close(fd);
186	        unlink(tmp);
187	        return -1;
188	    }
189	    fsync(fd);
190	    close(fd);
191	    if (rename(tmp, path) != 0) {
192	        perror("hybrid_handoff: rename");
193	        unlink(tmp);
194	        return -1;
195	    }
196	    return 0;
197	}
