199	static void on_handoff(unsigned int vcpu_idx, void *udata)
200	{
201	    const HandoffSite *site = (const HandoffSite *) udata;
202	    if (site->kind != HYBRID_HANDOFF_ENTER) return;
203	
204	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
205	    resolve_handles(v);
206	    struct hybrid_state_v1 s = {0};
207	    s.magic   = HYBRID_STATE_MAGIC;
208	    s.version = HYBRID_STATE_VERSION;
209	    s.flags   = HYBRID_FLAG_RV64;
210	    s.hart_id = vcpu_idx;
211	    s.priv    = 3;
212	    // PC via translation-time vaddr+size; reading the gdbstub PC inside the
213	    // exec callback can lag the actual current insn when V instructions
214	    // retire just before the trigger (TCG defers PC writes for performance).
215	    s.pc      = compute_handoff_pc(site);
216	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
217	
218	    // Floating-point: only set FP flag if at least one handle was bound,
219	    // i.e. QEMU advertised the FPU feature (D extension).
220	    int has_fp = 0;
221	    for (int i = 0; i < 32; i++) {
222	        s.fpr[i] = read_reg64(v->fpr[i]);
223	        if (v->fpr[i]) has_fp = 1;
224	    }
225	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
226	
227	    s.mstatus  = read_reg64(v->mstatus);
228	    s.mepc     = read_reg64(v->mepc);
229	    s.mtvec    = read_reg64(v->mtvec);
230	    s.mcause   = read_reg64(v->mcause);
231	    s.mtval    = read_reg64(v->mtval);
232	    s.mscratch = read_reg64(v->mscratch);
233	    s.medeleg  = read_reg64(v->medeleg);
234	    s.mideleg  = read_reg64(v->mideleg);
235	    s.mip      = read_reg64(v->mip);
236	    s.mie      = read_reg64(v->mie);
237	    s.mcycle   = read_reg64(v->mcycle);
238	    s.minstret = read_reg64(v->minstret);
239	    s.satp     = read_reg64(v->satp);
240	
241	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
242	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
243	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
244	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
245	
246	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
247	    // bounds the per-register byte count copied into vreg[].
248	    s.vstart = read_reg64(v->vstart);
249	    s.vxsat  = read_reg64(v->vxsat);
250	    s.vxrm   = read_reg64(v->vxrm);
251	    s.vcsr   = read_reg64(v->vcsr);
252	    s.vtype  = read_reg64(v->vtype);
253	    s.vl     = read_reg64(v->vl);
254	    s.vlenb  = read_reg64(v->vlenb);
255	    if (v->vlenb && s.vlenb > 0) {
256	        s.flags |= HYBRID_FLAG_V;
257	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
258	                     ? (size_t) s.vlenb
259	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
260	        for (int i = 0; i < 32; i++)
261	            (void) read_reg_bytes(v->vreg[i],
262	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
263	                                  bytes);
264	    }
265	
266	    if (write_state_atomic(&s, outfile_path) != 0) {
267	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
268	        exit(2);
269	    }
270	    fprintf(stderr,
271	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
272	            outfile_path, s.pc);
273	    // 200 == kExitHandoffToQemu in hybrid_vsim/src/hybrid/exit_codes.hpp.
274	    // Distinguishes drain from workload completion (0) so the orchestrator
275	    // can decide the next spawn.
276	    exit(200);
277	}
278	
279	// Per-insn tick for icount mode. udata is the per-insn HandoffSite
280	// pre-allocated at translation time, so on_handoff's compute_handoff_pc
281	// returns the lag-free post-trigger PC (same property as the CSR path).
282	static void on_icount_tick(unsigned int vcpu_idx, void *udata)
283	{
284	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
285	    if (++v->icount_retired < icount_target) return;
286	    on_handoff(vcpu_idx, udata);
287	}
288	
289	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
290	{
291	    (void) id;
292	    size_t n = qemu_plugin_tb_n_insns(tb);
293	    for (size_t i = 0; i < n; i++) {
294	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
295	
296	        if (icount_mode) {
297	            HandoffSite *site = g_new0(HandoffSite, 1);
298	            site->kind  = HYBRID_HANDOFF_ENTER;
299	            site->vaddr = qemu_plugin_insn_vaddr(insn);
300	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
301	            qemu_plugin_register_vcpu_insn_exec_cb(
302	                insn, on_icount_tick, QEMU_PLUGIN_CB_R_REGS, site);
303	        }
304	
305	        if (pc_mode) {
306	            // PC-trigger mode: vaddr-only match. qemu_plugin_insn_size lets
307	            // a future fixture park enter_pc on a compressed insn -- next-PC
308	            // is computed from the API-reported size, not assumed to be 4.
309	            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
310	            HandoffSite *site = g_new0(HandoffSite, 1);
311	            site->kind  = HYBRID_HANDOFF_ENTER;
312	            site->vaddr = qemu_plugin_insn_vaddr(insn);
313	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
314	            qemu_plugin_register_vcpu_insn_exec_cb(
315	                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
316	            continue;
317	        }
318	
319	        // CSR-trigger mode (default).
320	        size_t sz = qemu_plugin_insn_size(insn);
321	        if (sz != 4) continue;
322	        uint32_t raw = 0;
323	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
324	            continue;
325	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
326	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
327	        HandoffSite *site = g_new0(HandoffSite, 1);
328	        site->kind  = kind;
329	        site->vaddr = qemu_plugin_insn_vaddr(insn);
330	        site->size  = (uint32_t) sz;
331	        qemu_plugin_register_vcpu_insn_exec_cb(
332	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
333	    }
334	}
